public struct AssetCfa {
    public var assetId: ContractId
    public var name: String
    public var details: String?
    public var precision: UInt8
    public var issuedSupply: UInt64
    public var timestamp: Int64
    public var addedAt: Int64
    public var balance: AssetBalanceInfo
    public var media: Media?

    /// Default memberwise initializers are never public by default, so we
    /// declare one manually.
    public init(assetId: ContractId, name: String, details: String?, precision: UInt8, issuedSupply: UInt64, timestamp: Int64, addedAt: Int64, balance: AssetBalanceInfo, media: Media?) {
        self.assetId = assetId
        self.name = name
        self.details = details
        self.precision = precision
        self.issuedSupply = issuedSupply
        self.timestamp = timestamp
        self.addedAt = addedAt
        self.balance = balance
        self.media = media
    }
}

extension AssetCfa: Equatable, Hashable {
    public static func == (lhs: AssetCfa, rhs: AssetCfa) -> Bool {
        if lhs.assetId != rhs.assetId {
            return false
        }
        if lhs.name != rhs.name {
            return false
        }
        if lhs.details != rhs.details {
            return false
        }
        if lhs.precision != rhs.precision {
            return false
        }
        if lhs.issuedSupply != rhs.issuedSupply {
            return false
        }
        if lhs.timestamp != rhs.timestamp {
            return false
        }
        if lhs.addedAt != rhs.addedAt {
            return false
        }
        if lhs.balance != rhs.balance {
            return false
        }
        if lhs.media != rhs.media {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(assetId)
        hasher.combine(name)
        hasher.combine(details)
        hasher.combine(precision)
        hasher.combine(issuedSupply)
        hasher.combine(timestamp)
        hasher.combine(addedAt)
        hasher.combine(balance)
        hasher.combine(media)
    }
}

